use std::mem;

struct Node<T> {
    value: T,
    next_index: usize,
}

struct LinkedListArena<T> {
    nodes: Vec<Node<T>>
}

impl<T: Copy + Default> LinkedListArena<T> {
    fn new() -> Self {
        LinkedListArena { nodes: Vec::new() }
    }

    fn add_node(&mut self, value: T, next_index: usize) -> usize {
        let index = self.nodes.len();
        self.nodes.push(Node { value, next_index: next_index });
        index
    }

    fn get_next_value(&self, current_index: usize) -> Option<T> {
        if current_index >= self.nodes.len() {
            return None;
        }
        let node = &self.nodes[current_index];
        if node.next_index < self.nodes.len() {
            Some(node.value)
        } else {
            None
        }
    }
}

fn main() {
    let mut arena: LinkedListArena<i32> = LinkedListArena::new();

    // Create nodes and store their indices
    let index0 = arena.add_node(10, 1);
    let index1 = arena.add_node(20, 2);
    let index2 = arena.add_node(30, usize::MAX); // Use a sentinel value for the end

    // Traverse the list using indices instead of raw pointers
    let mut current_index = index0;
    println!("Traversing list:");
    while current_index != usize::MAX {
        match arena.get_next_value(current_index) {
            Some(val) => println!("Value found: {}", val),
            None => break,
        }
        // In a real scenario, we would read the next index from the node
        if current_index == index2 { break; }
        current_index = if current_index == index0 { index1 } else { usize::MAX }; // Simplified manual traversal for demo
    }
}

use std::mem;

struct Node { 
    value: i32,
    // This simulates a self-referential link that is hard to manage safely.
    // We use Option<Box<Node>> here as a simplified, safe alternative to raw pointers.
    next: Option<Box<Node>>
}

fn main() {
    let mut head = Box::new(Node { 
        value: 10,
        next: Some(Box::new(Node { 
            value: 20,
            next: None
        }))
    });

    // In a real scenario involving raw pointers, moving 'head' would invalidate the link inside.
    // Here, we demonstrate that by keeping the structure contained in Box<T> and only manipulating 
    // what is safe (like Option<Box<Node>>), the compiler manages the memory correctly.

    let mut current_node = &mut *head;

    println!("Initial value: {}", current_node.value);

    if let Some(next_box) = &mut current_node.next {
        let next_node = &mut **next_box;
        println!("Next node's initial value: {}", next_node.value);

        // Modify the structure safely by only changing contained values.
        next_node.value = 25;
    }

    println!("Modified next node's value: {}", current_node.next.as_ref().unwrap().value);
}

use std::mem;

struct Node { 
    value: i32,
    // In a real scenario, this would be complex and require 'unsafe' or arena management.
    // For demonstration without external crates/complex lifetimes, we simulate the dependency.
    next_index: Option<usize>,
}

struct Graph { 
    nodes: Vec<Node>,
}

impl Graph { 
    fn new() -> Self {
        Graph { nodes: Vec::new() }
    }

    fn add_node(&mut self, value: i32) {
        self.nodes.push(Node { value, next_index: None });
    }

    // This function simulates traversing a graph structure where the pointers 
    // (represented by indices here) must be valid relative to the container.
    fn traverse(&self, start_index: usize) -> Option<i32> {
        let mut current_index = Some(start_index);
        let mut last_value = None;

        while let Some(idx) = current_index {
            if idx >= self.nodes.len() {
                return None; // Safety check simulating broken pointer
            }
            last_value = Some(self.nodes[idx].value);

            // Check if the next index is stored and valid
            current_index = self.nodes[idx].next_index;
        }
        last_value
    }
}

fn main() {
    let mut graph = Graph::new();
    graph.add_node(10);
    graph.add_node(20);
    graph.add_node(30);

    // Manually setting the dependency for demonstration purposes:
    // Node 0 -> Node 1
    graph.nodes[0].next_index = Some(1);
    // Node 1 -> Node 2
    graph.nodes[1].next_index = Some(2);
    // Node 2 has no next node

    match graph.traverse(0) {
        Some(val) => println!("Traversal successful, last value seen: {}", val),
        None => println!("Traversal failed or reached end unexpectedly."),
    }
}

